INSERT INTO `olimpiada_disciplina` VALUES
(1,'FĂştbol','FĂştbol damas y varones. Partidos dirigidos por Ăˇrbitros oficiales, reglas FIFA con modificaciones propias del torneo.','equipo','partido','MĂ­nimo 07 jugadores inscritos para iniciar el partido; mĂˇximo 4 cambios por equipo.\nDuraciĂłn: 35\' x 35\' (40\' x 40\' en semifinal y final), 5\' de descanso entre tiempos.\nTolerancia: 10\' para el primer encuentro, 5\' para los siguientes.\nEmpate en semifinal/final se define por penales (5 por equipo, alternados), sin tiempo suplementario.\nPuntaje: Ganador 3 pts, Empate 1 pt, Perdedor 0 pts, W.O. -1 pt (rival gana 3-0).\nSanciones: suplantaciĂłn de jugador = W.O.; tarjeta roja no directa = 1 fecha; 2 tarjetas amarillas = 1 fecha de suspensiĂłn; agresiĂłn fĂ­sica o verbal = expulsiĂłn del campeonato.',18,'activa','2026-06-23 20:08:35'),
(2,'VĂłleibol','VĂłley femenino y masculino. Se juega con las reglas vigentes de la FIVB, sistema Rally Point.','equipo','partido','Planilla de juego: mĂˇximo 12 jugadores, mĂ­nimo 6 por partido.\nFase eliminatoria: 2 sets ganados de 20 puntos (tercer set a 15 en caso de empate 1-1).\nSemifinal y final: 2 sets ganados de 25 puntos (tercer set a 15).\nPuntaje: Partido ganado 2 pts, perdido 1 pt, W.O. 0 pts (rival gana 2-0 con parciales 25-0).\nJugador \'LĂ­bero\' opcional, con camiseta y nĂşmero distintos.',12,'activa','2026-06-23 20:08:35'),
(3,'BĂˇsquetbol','Baloncesto damas y varones. Arbitraje FIBA designado por la ComisiĂłn TĂ©cnica.','equipo','partido','Puntaje: Partido ganado 2 pts, perdido 1 pt, W.O. 0 pts (rival gana con score 30-0).\nTolerancia: 10\' en el primer encuentro, 5\' entre encuentros.\nFase eliminatoria: 2 tiempos de 15\' (12\' corridos + 3\' finales de tiempo efectivo), 1 tiempo tĂ©cnico por equipo y periodo.\nSemifinal y final: tiempo efectivo reglamentario.\nExpulsiĂłn del campo de juego: sanciĂłn automĂˇtica de 1 fecha (o mĂˇs segĂşn gravedad).',12,'activa','2026-06-23 20:08:35'),
(4,'Atletismo','Atletismo damas y varones (pistas, postas y campo). Se rige por el Reglamento Internacional de Atletismo (IAAF).','individual','posiciones','Pruebas: 100m, 200m, 400m, 800m, 1500m (damas) / 3000m (varones), postas 4x100m y 4x400m, salto alto, salto largo, triple, lanzamiento de bala/disco/jabalina.\nMĂˇximo 2 participantes por facultad en pruebas individuales; 1 equipo por facultad en cada posta.\nUn atleta puede correr hasta 4 pruebas individuales mĂˇs una colectiva (posta).\nPuntaje individual (8 mejores marcas): 10, 8, 6, 5, 4, 3, 2, 1. En postas, el doble: 20, 16, 12, 10, 8, 6, 4, 2.\nEl campeĂłn general se determina por la suma de puntos obtenidos en todas las pruebas.',NULL,'activa','2026-06-23 20:08:35'),
(5,'Ajedrez','Ajedrez por equipos de facultad (4 tableros). Se rige por las normas de la FIDE.','equipo','partido','Cada equipo: 4 jugadores inscritos en orden fijo, ocupando los tableros 1 a 4.\nPuntaje por partida: ganada 1 pt, empatada 0.5 pts, perdida 0 pts. El puntaje del match es la suma de las 4 partidas.\nTolerancia de 10\' para iniciar el match; mĂ­nimo 2 jugadores presentes para no perder por W.O.; 2 W.O. = eliminaciĂłn del equipo.\nDesempate en etapa eliminatoria: Sonnenborn-Berger, resultado entre empatados, partidas ganadas, partidas ganadas con negras, sorteo.\nDesempate en semifinal/final: nuevo match a 15\' por jugador (rĂˇpido); si persiste, 10\' (blitz); si persiste, partida Ăşnica a muerte sĂşbita (blancas 6\' vs negras 5\'; tablas favorece a negras).',4,'activa','2026-06-23 20:08:35'),
(6,'Tenis de Mesa','Tenis de mesa: dobles mixtos, individual damas e individual varones. Se rige por el Reglamento ITTF.','individual','posiciones','Cada facultad inscribe hasta 3 damas y 3 varones (mĂˇximo 6 deportistas).\nDobles mixtos: hasta 2 parejas por facultad, formadas por jugadores ya inscritos en individuales; sistema de eliminaciĂłn simple.\nIndividuales: sistema de series + llave de eliminaciĂłn simple.\nTodas las modalidades se juegan al mejor de 3 sets.\nPuntaje por puesto (igual en las 3 modalidades): 1Â° 20, 2Â° 15, 3Â° 12, 4Â° 10, 5Â° 9, 6Â° 8 puntos. El puntaje final de la facultad es la suma de lo obtenido en las 3 modalidades.\nTolerancia mĂˇxima de 5\' sobre el horario; vencido el plazo se resuelve por W.O.',6,'activa','2026-06-23 20:08:35'),
(7,'Futsal','Futsal damas y varones.','equipo','partido','Planilla de juego: hasta 10 jugadores; el equipo titular son 5 (uno arquero); cambios ilimitados por la zona de sustituciones.\nMĂ­nimo 5 jugadores para iniciar, de lo contrario W.O.\nTarjeta roja directa: sale del partido. Tarjeta amarilla: sale 3 minutos.\nFase eliminatoria: tiempo corrido 18\' x 18\'. Semifinal y final: tiempo efectivo 25\' x 25\', ambos con 5\' de descanso.\nEmpate en semifinal/final: penales alternados (3 iniciales, luego se continĂşa alternando hasta desempatar).\nPuntaje: Ganador 3 pts, Empate 1 pt, Perdedor 0 pts, W.O. -1 pt (rival gana 3-0).\nSanciones: suplantaciĂłn de jugador = eliminaciĂłn de la disciplina; tarjeta roja directa = 2 fechas; agresiĂłn fĂ­sica o verbal = expulsiĂłn del campeonato.',10,'activa','2026-06-24 05:33:11'),
(8,'Drill GimnĂˇstico / Gimnasia Aerobia','Gimnasia aerobia / drill gimnĂˇstico, calificada por jurado.','equipo','posiciones','Equipo de 15 a 20 participantes. Rutina musicalizada de 6\' a 8\' (tolerancia +/- 15-20 segundos).\nIngreso al escenario dentro de los 30 segundos de ser llamado (penalidad 0.5 pts si demora mĂˇs; W.O. si supera 60 segundos).\nCalificaciĂłn de un jurado de 3 jueces sobre 100 puntos: PresentaciĂłn 20, Desplazamiento 20, CoordinaciĂłn y ritmo 20, PirĂˇmides 20, CoreografĂ­a 20.\nSe registra la posiciĂłn y el puntaje obtenido por cada facultad participante.',20,'activa','2026-06-24 05:33:11'),
(9,'Juegos de Competencia','Circuito de 5 juegos recreativo-competitivos definidos por la comisiĂłn organizadora el dĂ­a del evento.','equipo','posiciones','Cada facultad inscribe 10 estudiantes (5 damas, 5 varones); admite hasta 4 inscritos adicionales como \'inscripciĂłn de emergencia\' si faltan titulares.\nSe desarrollan 5 juegos elegidos de una lista (fuerza en la soga, carrera de chasquis, carretilla humana, carrera de caballos, carrera de orientaciĂłn, el gusano humano, revienta globos, asignaciĂłn de tareas), anunciados 10 minutos antes de cada competencia.\nPuntaje por puesto: 1Â° 5 pts, 2Â° 4 pts, 3Â° 3 pts, 4Â° 2 pts, 5Â° 1 pt, 6Â° 0 pts. El puntaje final de la facultad es la suma de los 5 juegos.',10,'activa','2026-06-24 05:33:11'),
(10,'Tenis de Campo','Tenis de campo (singles) damas y varones.','individual','posiciones','MĂˇximo 2 deportistas por facultad en damas y 2 en varones (singles Ăşnicamente).\nEliminaciĂłn simple; si hay menos de 4 participantes, se juega round robin.\nSe juega al mejor de 2 sets; en caso de 1-1 se juega un match break a 10 puntos con diferencia de 2.\nPuntaje: Ganador 2 pts, Perdedor 1 pt, No presentado 0 pts. El cuadro final de facultades se obtiene del puntaje general de sus 2 competidores en cada categorĂ­a.\nSe rige por el reglamento de la FederaciĂłn Deportiva Peruana de Tenis.',4,'activa','2026-06-24 05:33:11'),
(11,'NataciĂłn','NataciĂłn damas y varones, series finales por tiempo. Se rige por el reglamento de la FINA.','individual','posiciones','Pruebas: 50m libre, espalda, pecho y mariposa; posta 4x50m libre; posta 4x50m combinado; 200m combinado (damas y varones).\nCada nadador participa en mĂˇximo 4 pruebas individuales mĂˇs una posta. MĂˇximo 2 nadadores por facultad por prueba; 1 posta por facultad en cada posta.\nCada facultad inscribe un delegado titular responsable de la ficha de inscripciĂłn y cambios.\nPuntaje (8 mejores tiempos): 10, 8, 6, 5, 4, 3, 2, 1; en postas el doble.\nCampeĂłn general: mayor puntaje acumulado; en caso de empate se decide por mayor cantidad de primeros lugares, luego segundos, y asĂ­ sucesivamente.',NULL,'activa','2026-06-24 05:33:11'),
(12,'TriatlĂłn','TriatlĂłn damas y varones: nataciĂłn + ciclismo + carrera, de forma continua.','individual','posiciones','MĂˇximo 10 deportistas por facultad en damas y 10 en varones.\nRecorrido continuo: nataciĂłn 50m + ciclismo 9km + carrera 4km. Cada deportista trae su propia bicicleta.\nSanciĂłn a quien no cumpla el volumen mĂ­nimo de cada tramo por omisiĂłn o fraude.\nPuntaje por equipo (15 mejores puestos): 1Â° 20, 2Â° 16, 3Â° 14, 4Â° 12, 5Â° 11, 6Â° 10, 7Â° 9, 8Â° 8, 9Â° 7, 10Â° 6, 11Â° 5, 12Â° 4, 13Â° 3, 14Â° 2, 15Â° 1 punto.\nSe premian los 3 primeros lugares de cada categorĂ­a (damas y varones).',20,'activa','2026-06-24 05:33:11'),
(13,'Billar Federado','Billar federado, modalidad pool/billar americano.','individual','posiciones','Cada facultad inscribe hasta 4 estudiantes (damas y/o varones).\nSistema de eliminaciĂłn simple, competencia en un solo dĂ­a hĂˇbil.\nPuntaje por puesto (10 mejores): 1Â° 10, 2Â° 8, 3Â° 7, 4Â° 6, 5Â° 5, 6Â° 4, 7Â° 3, 8Â° 2, 9Â° 1, 10Â° 0.5 puntos.\nEl puntaje final de la facultad es la suma de los puntos de todos sus competidores.',4,'activa','2026-06-24 05:33:11'),
(14,'MaratĂłn','MaratĂłn damas y varones por equipos de facultad.','individual','posiciones','Cada facultad inscribe hasta 12 participantes en damas y 12 en varones.\nPuntaje por equipo segĂşn el orden de llegada de los primeros 15 corredores de cada facultad (puntaje por equipos, no individual): 1Â° 20, 2Â° 16, 3Â° 14, 4Â° 12, 5Â° 11, 6Â° 10, 7Â° 9, 8Â° 8, 9Â° 7, 10Â° 6, 11Â° 5, 12Â° 4, 13Â° 3, 14Â° 2, 15Â° 1 punto.',24,'activa','2026-06-24 05:33:11'),
(15,'Ciclismo','Ciclismo de ruta y/o circuito, damas y varones.','individual','posiciones','Cada facultad inscribe hasta 8 damas y 8 varones.\nModalidad ruta y/o circuito; sistema todos contra todos. Equipo obligatorio: casco, guantes, lentes, protectores de rodilla y bicicleta propia.\nDescalificaciĂłn por incumplir la ruta establecida, suplantaciĂłn de persona o atajar la ruta.\nPuntaje por puesto (10 mejores): 1Â° 10, 2Â° 8, 3Â° 7, 4Â° 6, 5Â° 5, 6Â° 4, 7Â° 3, 8Â° 2, 9Â° 1, 10Â° 0.5 puntos.',16,'activa','2026-06-24 05:33:11'),
(16,'InauguraciĂłn / Desfile','CalificaciĂłn del desfile inaugural de cada delegaciĂłn. Otorga puntos adicionales al cuadro general.','equipo','posiciones','Las delegaciones deben presentarse en el punto de encuentro a la hora indicada para iniciar el desfile; una vez cerrado el ingreso no se admiten mĂˇs delegaciones.\nCalificaciĂłn del 1 al 10 segĂşn: puntualidad, presentaciĂłn, orden y originalidad (pancartas, mascotas, disfraces, etc.).\nConteo de delegaciĂłn: alumnos matriculados de la facultad, acompaĂ±ados de su madrina y docentes; formaciĂłn en filas de 3 o 4.\nProhibido el uso de artefactos pirotĂ©cnicos, salvo bengalas.\nLos puntos obtenidos se suman como puntaje adicional al cuadro general de la facultad.',NULL,'activa','2026-06-24 05:33:11'),
(17,'Caminata','Caminata de motivaciĂłn de cada delegaciĂłn. Otorga puntos adicionales al cuadro general.','equipo','posiciones','Las delegaciones deben presentarse en el punto de partida a la hora indicada; iniciada la caminata no se modifica el orden de las delegaciones.\nCalificaciĂłn del 1 al 10 segĂşn: puntualidad, presentaciĂłn, orden y originalidad (pancartas, mascotas, disfraces, etc.).\nFormaciĂłn en filas de 3 o 4 segĂşn el nĂşmero de integrantes de cada facultad.\nProhibido el uso de artefactos pirotĂ©cnicos, salvo bengalas.\nLos puntos obtenidos se suman como puntaje adicional al cuadro general de la facultad.',NULL,'activa','2026-06-24 05:33:11');
