INSERT INTO `olimpiada_post` VALUES
(4,1,'ÂˇArrancan las Olimpiadas Interfacultades 2025!','Con un emotivo desfile de inauguraciĂłn en el Estadio Jorge Basadre, dio inicio la ediciĂłn 2026 de las Olimpiadas Interfacultades UPT. MĂˇs de 140 estudiantes representarĂˇn a sus 6 facultades en 17 disciplinas durante las prĂłximas semanas. ÂˇQue gane el mejor equipo!','https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRstJR39GC8Xdncgm48MUf8DmDcJ8PTYT6g4Q5oX6QH_HhWiFQ05NnQ6dBc&s=10','ComitĂ© OlĂ­mpico UPT','2026-06-24 17:39:04'),
(5,1,'FĂştbol varones: la Facultad de IngenierĂ­a arranca firme','En un partidazo en el Estadio Paillardelli, FAING venciĂł 3-1 a FADE en la jornada inaugural del fĂştbol varones. Carlos Mamani fue la figura del partido con un doblete.','https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQEhkEc4dRKS2VFnMwNMd6wZCzV6Ub9rMlTH-6pOxNDZPys0OETJSqYGgVL&s=10','Prensa Deportiva UPT','2026-06-24 17:39:04'),
(6,1,'Atletismo: FAING lidera la clasificaciĂłn general','Tras la primera jornada de pistas en el Coliseo UPT, la Facultad de IngenierĂ­a se queda con el primer lugar en los 100m varones. La competencia por el medallero general estĂˇ mĂˇs reĂ±ida que nunca.','https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSv3xLVtRpASQ1ypY1iHSoIOyhhT3T6BzQBXzKzSpb8MCssgG8NcxKd_YRu&s=10','ComitĂ© OlĂ­mpico UPT','2026-06-24 17:39:05');
