INSERT INTO `parties` VALUES
(1,1,'Fuerza UPT','#22c55e','https://ui-avatars.com/api/?name=Fuerza+UPT&background=22c55e&color=fff&size=200','Somos una organizaciĂłn juvenil de la Universidad Privada de Tacna. Nuestro propĂłsito: ser la voz, la acciĂłn y el impulso de la juventud universitaria. Lema: \"LA EVOLUCIĂ“N\".','2026-06-30 04:53:03','2026-06-30 04:53:03'),
(2,1,'REU UPT','#3b82f6','https://ui-avatars.com/api/?name=REU+UPT&background=3b82f6&color=eab308&size=200','RENOVACIĂ“N UNIVERSITARIA â€“ La mejor organizaciĂłn estudiantil de la UPT te estĂˇ esperando. Haz nuevos amigos, aprende en grande, vive experiencias Ăşnicas, desarrolla tu liderazgo, crece personal y profesionalmente.','2026-06-30 04:53:03','2026-06-30 04:53:03'),
(3,1,'FEUT UPT','#a855f7','https://ui-avatars.com/api/?name=FEUT+UPT&background=a855f7&color=fff&size=200','Nueva lista candidata para el periodo 2026-2027. Promoviendo la participaciĂłn estudiantil activa en la Universidad Privada de Tacna.','2026-06-30 04:53:03','2026-06-30 04:53:03');
